const SANS = "Unbounded, system-ui, -apple-system, BlinkMacSystemFont, Segoe UI, sans-serif";
const MONO = "Geist Mono, ui-monospace, SFMono-Regular, Menlo, Consolas, monospace";

function themeColors() {
  const isDark = document.documentElement.classList.contains("dark");
  return {
    isDark,
    bg: isDark ? "#09090b" : "#f5f5f0", // Cream/Bone for light mode
    surface: isDark ? "#18181b" : "#e8e8e3",
    text: isDark ? "#fafafa" : "#18181b",
    muted: isDark ? "#a1a1aa" : "#52525b",
    subtle: isDark ? "#52525b" : "#71717a",
    accent: isDark ? "#10b981" : "#059669", // Emerald
    accentSoft: isDark ? "#064e3b" : "#dcfce7",
    warning: isDark ? "#f59e0b" : "#d97706", // Amber
    error: isDark ? "#ef4444" : "#dc2626", // Red
    border: isDark ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.12)",
    grid: isDark ? "rgba(255,255,255,0.03)" : "rgba(0,0,0,0.04)",
    glowPrimary: isDark ? "rgba(16,185,129,0.12)" : "rgba(16,185,129,0.1)",
    glowSecondary: isDark ? "rgba(245,158,11,0.08)" : "rgba(245,158,11,0.06)",
  };
}

const CARD = { width: 1200, height: 630 };

function roundRect(ctx, x, y, w, h, r) {
  const radius = Math.min(r, w / 2, h / 2);
  ctx.beginPath();
  ctx.moveTo(x + radius, y);
  ctx.arcTo(x + w, y, x + w, y + h, radius);
  ctx.arcTo(x + w, y + h, x, y + h, radius);
  ctx.arcTo(x, y + h, x, y, radius);
  ctx.arcTo(x, y, x + w, y, radius);
  ctx.closePath();
}

function fillRoundRect(ctx, x, y, w, h, r, fill, stroke = null) {
  roundRect(ctx, x, y, w, h, r);
  ctx.fillStyle = fill;
  ctx.fill();
  if (stroke) {
    ctx.strokeStyle = stroke;
    ctx.lineWidth = 1;
    ctx.stroke();
  }
}

function drawGrid(ctx, w, h, color) {
  ctx.save();
  ctx.strokeStyle = color;
  ctx.lineWidth = 1;
  const size = 40;
  for (let x = 0; x <= w; x += size) {
    ctx.beginPath();
    ctx.moveTo(x, 0);
    ctx.lineTo(x, h);
    ctx.stroke();
  }
  for (let y = 0; y <= h; y += size) {
    ctx.beginPath();
    ctx.moveTo(0, y);
    ctx.lineTo(w, y);
    ctx.stroke();
  }
  ctx.restore();
}

function drawGlow(ctx, x, y, radius, color, w, h) {
  const gradient = ctx.createRadialGradient(x, y, 0, x, y, radius);
  gradient.addColorStop(0, color);
  gradient.addColorStop(1, "transparent");
  ctx.save();
  ctx.globalCompositeOperation = "screen";
  ctx.fillStyle = gradient;
  ctx.fillRect(0, 0, w, h);
  ctx.restore();
}

function drawLabel(ctx, text, x, y, color) {
  ctx.font = `800 11px ${MONO}`;
  ctx.fillStyle = color;
  ctx.fillText(String(text || "").toUpperCase(), x, y);
}

function drawTopItems(ctx, items, x, y, width, t) {
  drawLabel(ctx, "Frequent listings", x, y, t.muted);
  const list = Array.isArray(items) ? items.slice(0, 3) : [];
  if (list.length === 0) {
    ctx.font = `600 12px ${SANS}`;
    ctx.fillStyle = t.subtle;
    ctx.fillText("No recent activity data.", x, y + 30);
    return;
  }

  list.forEach((item, i) => {
    const iy = y + 18 + i * 54;
    fillRoundRect(ctx, x, iy, width, 44, 8, t.surface, t.border);
    
    ctx.font = `800 13px ${SANS}`;
    ctx.fillStyle = t.text;
    ctx.fillText(item.itemName || "Item", x + 12, iy + 26);
    
    ctx.font = `900 14px ${MONO}`;
    ctx.fillStyle = t.accent;
    ctx.textAlign = "right";
    ctx.fillText(fmt(item.unitPrice || 0), x + width - 12, iy + 27);
    ctx.textAlign = "left";
  });
}

function fmt(n) {
  if (n >= 1000000) return (n / 1000000).toFixed(1) + "M";
  if (n >= 1000) return (n / 1000).toFixed(1) + "K";
  return String(n);
}

function getAccuracyStyle(label, t) {
  const styles = {
    "Very High": { color: t.accent, bg: t.accent + "1A", border: t.accent + "33", icon: "✓" },
    Trustworthy: { color: t.accent, bg: t.accent + "1A", border: t.accent + "33", icon: "✓" },
    High: { color: t.accent, bg: t.accent + "1A", border: t.accent + "33", icon: "✓" },
    Suspicious: { color: t.warning, bg: t.warning + "1A", border: t.warning + "33", icon: "!" },
    Flagged: { color: t.error, bg: t.error + "1A", border: t.error + "33", icon: "×" },
    Neutral: { color: t.subtle, bg: t.surface, border: t.border, icon: "•" },
  };
  return styles[label] || styles.Neutral;
}

export async function renderSellerCardToBlob(seller) {
  const { name, totalListings, validListings, avgMarkupPercent, overpricedRatio, accuracyLabel, isBlacklisted, topItems } = seller || {};
  const t = themeColors();
  const v = CARD;
  return new Promise((resolve, reject) => {
    const canvas = document.createElement("canvas");
    canvas.width = v.width;
    canvas.height = v.height;
    const ctx = canvas.getContext("2d");
    if (!ctx) { reject(new Error("Canvas is unavailable")); return; }

    ctx.fillStyle = t.bg;
    ctx.fillRect(0, 0, v.width, v.height);
    
    // Background glows
    drawGlow(ctx, v.width - 200, 100, 600, t.glowPrimary, v.width, v.height);
    drawGlow(ctx, 100, v.height - 100, 500, t.glowSecondary, v.width, v.height);
    
    drawGrid(ctx, v.width, v.height, t.grid);

    // Header
    ctx.save();
    ctx.font = `900 12px ${MONO}`;
    ctx.fillStyle = t.accent;
    ctx.beginPath();
    ctx.arc(62, 46, 4, 0, Math.PI * 2);
    ctx.fill();
    ctx.fillText("CMI SELLER", 74, 50);
    
    ctx.fillStyle = t.subtle;
    ctx.textAlign = "right";
    ctx.font = `700 11px ${MONO}`;
    ctx.fillText(new Date().toUTCString().slice(5, 16).toUpperCase(), v.width - 56, 50);
    ctx.restore();

    // Seller name & Verification
    ctx.font = `900 64px ${SANS}`;
    ctx.fillStyle = t.text;
    ctx.letterSpacing = "-0.02em";
    const nameDisplay = name || "Unknown Seller";
    const nameWidth = ctx.measureText(nameDisplay.length > 20 ? nameDisplay.slice(0, 18) + "..." : nameDisplay).width;
    ctx.fillText(nameDisplay.length > 20 ? nameDisplay.slice(0, 18) + "..." : nameDisplay, 56, 135);
    ctx.letterSpacing = "normal";

    const badge = getAccuracyStyle(accuracyLabel, t);
    if (badge.icon === "✓") {
      ctx.fillStyle = t.accent;
      ctx.beginPath();
      ctx.arc(56 + nameWidth + 30, 112, 14, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = t.bg;
      ctx.font = `900 16px ${MONO}`;
      ctx.textAlign = "center";
      ctx.fillText("V", 56 + nameWidth + 30, 118);
      ctx.textAlign = "left";
    }

    // Sub-title / Status
    ctx.font = `700 14px ${MONO}`;
    ctx.fillStyle = badge.color;
    ctx.fillText(`${(accuracyLabel || "Neutral").toUpperCase()} SELLER • VERIFIED`, 56, 170);

    // Accuracy badge (Top Right)
    const label = (accuracyLabel || "Neutral").toUpperCase();
    ctx.font = `900 14px ${MONO}`;
    ctx.fillStyle = badge.color;
    fillRoundRect(ctx, v.width - 200, 100, 144, 34, 6, badge.bg, badge.border);
    ctx.textAlign = "center";
    ctx.fillText(label, v.width - 200 + 72, 122);
    ctx.textAlign = "left";

    // Stats grid
    const contentX = 56;
    const contentY = 220;
    const statsWidth = 840;
    const gutter = 20;
    const boxW = (statsWidth - gutter * 3) / 4;

    function drawStatBox(labelText, value, x, y, note = "") {
      fillRoundRect(ctx, x, y, boxW, 140, 16, t.surface, t.border);
      
      // Icon placeholder / small decoration
      ctx.fillStyle = t.accent;
      ctx.globalAlpha = 0.15;
      ctx.beginPath();
      ctx.arc(x + 24, y + 30, 10, 0, Math.PI * 2);
      ctx.fill();
      ctx.globalAlpha = 1.0;

      ctx.font = `800 10px ${MONO}`;
      ctx.fillStyle = t.muted;
      ctx.fillText(labelText.toUpperCase(), x + 20, y + 65);
      
      ctx.font = `900 32px ${MONO}`;
      ctx.fillStyle = t.text;
      ctx.fillText(value, x + 20, y + 100);
      
      if (note) {
        ctx.font = `700 9px ${MONO}`;
        ctx.fillStyle = t.subtle;
        ctx.fillText(note.toUpperCase(), x + 20, y + 122);
      }
    }

    drawStatBox("Total Listings", String(totalListings || "0"), contentX, contentY, "All time");
    drawStatBox("Active Listings", String(validListings || "0"), contentX + (boxW + gutter), contentY, "Live in market");
    drawStatBox("Avg. Markup", fmtPercent(avgMarkupPercent), contentX + (boxW + gutter) * 2, contentY, "Below Median");
    drawStatBox("Overpriced", fmtPercent(overpricedRatio, true), contentX + (boxW + gutter) * 3, contentY, "≤ 110% of Median");

    // Risk indicator / Market Integrity Section
    const riskY = contentY + 180;
    drawLabel(ctx, "Market Integrity", contentX, riskY, t.muted);

    const riskBarY = riskY + 24;
    const riskBarWidth = 400;
    const riskVal = Math.min(1, Math.max(0, ((avgMarkupPercent || 0) + 20) / 100));
    const riskColor = riskVal > 0.6 ? t.error : riskVal > 0.3 ? t.warning : t.accent;
    
    fillRoundRect(ctx, contentX, riskBarY, riskBarWidth, 12, 6, t.surface, t.border);
    fillRoundRect(ctx, contentX, riskBarY, riskBarWidth * riskVal, 12, 6, riskColor);

    ctx.font = `700 10px ${MONO}`;
    ctx.fillStyle = t.subtle;
    ctx.fillText("Lower markup indicates better value for buyers.", contentX, riskBarY + 32);

    // Trust Score Section (Bottom Left)
    const trustX = contentX;
    const trustY = riskBarY + 80;
    drawLabel(ctx, "Trust Score", trustX, trustY, t.muted);
    
    ctx.font = `900 64px ${SANS}`;
    ctx.fillStyle = t.text;
    const scoreVal = Math.round((1 - (overpricedRatio || 0)) * 100);
    ctx.fillText(String(scoreVal), trustX, trustY + 70);
    
    ctx.font = `700 24px ${MONO}`;
    ctx.fillStyle = t.muted;
    ctx.fillText("/100", trustX + ctx.measureText(String(scoreVal)).width + 4, trustY + 65);

    const scoreLabel = scoreVal > 80 ? "EXCELLENT" : scoreVal > 50 ? "GOOD" : "POOR";
    const scoreColor = scoreVal > 80 ? t.accent : scoreVal > 50 ? t.warning : t.error;
    
    ctx.font = `900 14px ${MONO}`;
    ctx.fillStyle = scoreColor;
    const labelW = ctx.measureText(scoreLabel).width + 16;
    fillRoundRect(ctx, trustX, trustY + 85, labelW, 28, 4, scoreColor + "1A", scoreColor + "33");
    ctx.textAlign = "center";
    ctx.fillText(scoreLabel, trustX + labelW / 2, trustY + 104);
    ctx.textAlign = "left";

    // Right Sidebar / Stats Summary
    const sideX = contentX + statsWidth + 40;
    // drawTopItems could be called here or custom sidebar logic
    drawTopItems(ctx, topItems || [], sideX, contentY, v.width - sideX - 56, t);


    // Status Footer
    const footerY = v.height - 30;
    ctx.font = `800 10px ${MONO}`;
    ctx.fillStyle = t.muted;
    ctx.fillText("CASTIA MARKET INSIGHT", 56, footerY);
    
    ctx.textAlign = "right";
    ctx.fillStyle = t.subtle;
    ctx.fillText("DATA AGGREGATED BY LEKTO_", v.width - 56, footerY);
    
    if (isBlacklisted) {
      ctx.fillStyle = t.error;
      ctx.fillText("RESTRICTED TRADER", v.width - 56, footerY - 18);
    }
    ctx.restore();

    canvas.toBlob((blob) => {
      if (blob) resolve(blob);
      else reject(new Error("PNG export failed"));
    }, "image/png");
  });
}

function fmtPercent(n, isFraction = false) {
  if (n == null) return "—";
  const val = isFraction ? n * 100 : n;
  return `${val >= 0 ? "+" : ""}${val.toFixed(1)}%`;
}

export async function downloadSellerCard(seller) {
  const blob = await renderSellerCardToBlob(seller);
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = `${(seller.name || "seller").replace(/\s+/g, "-")}-trading-card.png`;
  a.click();
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}
