import { useState, useEffect } from 'react';

const PREFERENCES_KEY = 'castia.preferences';

// Default preferences
const DEFAULT_PREFERENCES = {
  theme: 'dark', // 'dark' or 'light'
  priceFormat: 'compact', // 'compact' or 'full'
  notifications: {
    priceAlerts: true,
    systemUpdates: true,
  },
  dashboardLayout: 'default', // 'default' or 'compact'
  listingDensity: 'comfortable', // 'comfortable' or 'compact'
};

// Read preferences from localStorage
function readPreferences() {
  try {
    const raw = localStorage.getItem(PREFERENCES_KEY);
    if (!raw) return DEFAULT_PREFERENCES;
    const data = JSON.parse(raw);
    
    // Migrate old preferences if needed
    return {
      ...DEFAULT_PREFERENCES,
      ...data,
      // Ensure all required fields exist
      theme: data.theme || DEFAULT_PREFERENCES.theme,
      priceFormat: data.priceFormat || DEFAULT_PREFERENCES.priceFormat,
      notifications: {
        ...DEFAULT_PREFERENCES.notifications,
        ...data.notifications,
      },
      dashboardLayout: data.dashboardLayout || DEFAULT_PREFERENCES.dashboardLayout,
      listingDensity: data.listingDensity || DEFAULT_PREFERENCES.listingDensity,
    };
  } catch {
    return DEFAULT_PREFERENCES;
  }
}

// Write preferences to localStorage and dispatch update event
function writePreferences(preferences) {
  try {
    localStorage.setItem(PREFERENCES_KEY, JSON.stringify(preferences));
    window.dispatchEvent(new CustomEvent('castia:preferences'));
  } catch { /* ignore */ }
}

// Custom hook for managing user preferences
export function usePreferences() {
  const [preferences, setPreferences] = useState(readPreferences());

  // Load preferences on mount and subscribe to updates
  useEffect(() => {
    const handleUpdate = () => setPreferences(readPreferences());
    window.addEventListener('castia:preferences', handleUpdate);
    window.addEventListener('storage', handleUpdate);
    return () => {
      window.removeEventListener('castia:preferences', handleUpdate);
      window.removeEventListener('storage', handleUpdate);
    };
  }, []);

  // Update preferences with validation
  const updatePreferences = (updates) => {
    setPreferences((prev) => {
      const next = { ...prev, ...updates };
      writePreferences(next);
      return next;
    });
  };

  return {
    preferences,
    updatePreferences,
    // Convenience methods for specific preferences
    setTheme: (theme) => updatePreferences({ theme }),
    setPriceFormat: (format) => updatePreferences({ priceFormat: format }),
    setNotificationPref: (type, enabled) => {
      updatePreferences({
        notifications: {
          ...preferences.notifications,
          [type]: enabled,
        },
      });
    },
    setDashboardLayout: (layout) => updatePreferences({ dashboardLayout: layout }),
    setListingDensity: (density) => updatePreferences({ listingDensity: density }),
  };
}